import React from 'react';
import styles from './stepper.module.css';
import Step from './step';

interface StepperProps {
  active: string;
  passed: string;
}

const steps = [
  { to: "/cart", text: "Cart" },
  { to: "/checkout/details", text: "Details" },
  { to: "/checkout/shipping", text: "Shipping" },
  { to: "/checkout/payment", text: "Payment" },
];

const Stepper: React.FC<StepperProps> = ({ active, passed }) => {
  return (
    <div className={styles.stepper}>
      {steps.map((step, index) => (
        <React.Fragment key={step.to}>
          <Step
            to={step.to}
            text={step.text}
            className={`${styles.stepper_item} ${
              active === step.text ? styles.stepper_active : (passed === step.text ? styles.stepper_passed : "")
            }`}
          />
          {index < steps.length - 1 && <span className={styles.stepper_separator}>

            </span>}
        </React.Fragment>
      ))}
    </div>
  );
}

export default Stepper;




